  1→import { TimelineManager } from './manager';
  2→
  3→function isGeminiConversationRoute(pathname = location.pathname): boolean {
  4→  // Support account-scoped routes like /u/1/app or /u/0/gem/
  5→  // Matches: "/app", "/gem/", "/u/<num>/app", "/u/<num>/gem/"
  6→  return /^\/(?:u\/\d+\/)?(app|gem)(\/|$)/.test(pathname);
  7→}
  8→
  9→type HistoryStateArgs = Parameters<History['pushState']>;
 10→
 11→let timelineManagerInstance: TimelineManager | null = null;
 12→let currentUrl = location.href;
 13→let currentPathAndSearch = location.pathname + location.search;
 14→let routeCheckIntervalId: number | null = null;
 15→let routeListenersAttached = false;
 16→let activeObservers: MutationObserver[] = [];
 17→let cleanupHandlers: (() => void)[] = [];
 18→let historyPatched = false;
 19→let originalPushState: History['pushState'] | null = null;
 20→let originalReplaceState: History['replaceState'] | null = null;
 21→
 22→function initializeTimeline(): void {
 23→  if (timelineManagerInstance) {
 24→    try {
 25→      timelineManagerInstance.destroy();
 26→    } catch {}
 27→    timelineManagerInstance = null;
 28→  }
 29→  try {
 30→    document.querySelector('.gemini-timeline-bar')?.remove();
 31→  } catch {}
 32→  try {
 33→    document.querySelector('.timeline-left-slider')?.remove();
 34→  } catch {}
 35→  try {
 36→    document.getElementById('gemini-timeline-tooltip')?.remove();
 37→  } catch {}
 38→  timelineManagerInstance = new TimelineManager();
 39→  timelineManagerInstance
 40→    .init()
 41→    .catch((err) => console.error('Timeline initialization failed:', err));
 42→}
 43→
 44→let urlChangeTimer: number | null = null;
 45→
 46→function handleUrlChange(): void {
 47→  if (location.href === currentUrl) return;
 48→
 49→  const newPathAndSearch = location.pathname + location.search;
 50→  const pathChanged = newPathAndSearch !== currentPathAndSearch;
 51→
 52→  // Update current URL
 53→  currentUrl = location.href;
 54→
 55→  // Only reinitialize if pathname or search changed, not just hash
 56→  if (!pathChanged) {
 57→    console.log('[Timeline] Only hash changed, keeping existing timeline');
 58→    return;
 59→  }
 60→
 61→  currentPathAndSearch = newPathAndSearch;
 62→
 63→  // Clear any pending initialization
 64→  if (urlChangeTimer) {
 65→    clearTimeout(urlChangeTimer);
 66→    urlChangeTimer = null;
 67→  }
 68→
 69→  if (isGeminiConversationRoute()) {
 70→    // Add delay to allow DOM to update after SPA navigation
 71→    console.log('[Timeline] URL changed to conversation route, scheduling initialization');
 72→    urlChangeTimer = window.setTimeout(() => {
 73→      console.log('[Timeline] Initializing timeline after URL change');
 74→      initializeTimeline();
 75→      urlChangeTimer = null;
 76→    }, 500); // Wait for DOM to settle
 77→  } else {
 78→    console.log('[Timeline] URL changed to non-conversation route, cleaning up');
 79→    if (timelineManagerInstance) {
 80→      try {
 81→        timelineManagerInstance.destroy();
 82→      } catch {}
 83→      timelineManagerInstance = null;
 84→    }
 85→    try {
 86→      document.querySelector('.gemini-timeline-bar')?.remove();
 87→    } catch {}
 88→    try {
 89→      document.querySelector('.timeline-left-slider')?.remove();
 90→    } catch {}
 91→    try {
 92→      document.getElementById('gemini-timeline-tooltip')?.remove();
 93→    } catch {}
 94→  }
 95→}
 96→
 97→function patchHistoryOnce(): void {
 98→  if (historyPatched) return;
 99→  try {
100→    originalPushState = history.pushState;
101→    originalReplaceState = history.replaceState;
102→
103→    history.pushState = (...args: HistoryStateArgs): void => {
104→      originalPushState?.apply(history, args);
105→      handleUrlChange();
106→    };
107→    history.replaceState = (...args: HistoryStateArgs): void => {
108→      originalReplaceState?.apply(history, args);
109→      handleUrlChange();
110→    };
111→
112→    historyPatched = true;
113→    cleanupHandlers.push(() => {
114→      if (!historyPatched) return;
115→      if (originalPushState) history.pushState = originalPushState;
116→      if (originalReplaceState) history.replaceState = originalReplaceState;
117→      historyPatched = false;
118→      originalPushState = null;
119→      originalReplaceState = null;
120→    });
121→  } catch (e) {
122→    console.warn('[Timeline] Failed to patch history API:', e);
123→  }
124→}
125→
126→function attachRouteListenersOnce(): void {
127→  if (routeListenersAttached) return;
128→  routeListenersAttached = true;
129→  patchHistoryOnce();
130→  window.addEventListener('popstate', handleUrlChange);
131→  window.addEventListener('hashchange', handleUrlChange);
132→  routeCheckIntervalId = window.setInterval(() => {
133→    if (location.href !== currentUrl) handleUrlChange();
134→  }, 800);
135→
136→  // Register cleanup handlers for proper resource management
137→  cleanupHandlers.push(() => {
138→    window.removeEventListener('popstate', handleUrlChange);
139→    window.removeEventListener('hashchange', handleUrlChange);
140→  });
141→}
142→
143→/**
144→ * Cleanup function to prevent memory leaks
145→ * Disconnects all observers, clears intervals, and removes event listeners
146→ */
147→function cleanup(): void {
148→  // Cancel any pending delayed initialization
149→  if (urlChangeTimer) {
150→    clearTimeout(urlChangeTimer);
151→    urlChangeTimer = null;
152→  }
153→
154→  // Disconnect all active MutationObservers
155→  activeObservers.forEach((observer) => {
156→    try {
157→      observer.disconnect();
158→    } catch (e) {
159→      console.error('[Gemini Voyager] Failed to disconnect observer during cleanup:', e);
160→    }
161→  });
162→  activeObservers = [];
163→
164→  // Clear the route check interval
165→  if (routeCheckIntervalId !== null) {
166→    clearInterval(routeCheckIntervalId);
167→    routeCheckIntervalId = null;
168→  }
169→
170→  // Execute all registered cleanup handlers
171→  cleanupHandlers.forEach((handler) => {
172→    try {
173→      handler();
174→    } catch (e) {
175→      console.error('[Gemini Voyager] Failed to run cleanup handler:', e);
176→    }
177→  });
178→  cleanupHandlers = [];
179→
180→  // Reset flag
181→  routeListenersAttached = false;
182→}
183→
184→export function startTimeline(): void {
185→  const setup = (): void => {
186→    attachRouteListenersOnce();
187→    if (isGeminiConversationRoute() && !timelineManagerInstance) {
188→      initializeTimeline();
189→    }
190→  };
191→
192→  if (document.body) {
193→    setup();
194→  } else {
195→    const initialObserver = new MutationObserver(() => {
196→      if (!document.body) return;
197→
198→      // Disconnect and remove from tracking
199→      initialObserver.disconnect();
200→      activeObservers = activeObservers.filter((obs) => obs !== initialObserver);
201→
202→      setup();
203→    });
204→
205→    // Track observer for cleanup
206→    activeObservers.push(initialObserver);
207→    initialObserver.observe(document.documentElement || document.body, {
208→      childList: true,
209→      subtree: true,
210→    });
211→  }
212→
213→  // Setup cleanup on page unload
214→  window.addEventListener('beforeunload', cleanup, { once: true });
215→
216→  // Also cleanup on extension unload (if content script is removed)
217→  if (typeof chrome !== 'undefined' && chrome.runtime) {
218→    chrome.runtime.onSuspend?.addListener?.(cleanup);
219→  }
220→}
