 1→/**
 2→ * Keyboard Shortcut Types
 3→ * Defines types for configurable keyboard shortcuts
 4→ *
 5→ * Supports:
 6→ * - Single key mode (e.g., j/k for vim-style navigation)
 7→ * - Combination key mode (e.g., Alt + Arrow keys)
 8→ * - Fully customizable by user
 9→ */
10→
11→/**
12→ * Modifier keys for shortcuts
13→ */
14→export type ModifierKey = 'Alt' | 'Ctrl' | 'Shift' | 'Meta';
15→
16→/**
17→ * Any key can be used for shortcuts
18→ * We use string to support any keyboard key
19→ */
20→export type ShortcutKey = string;
21→
22→/**
23→ * Shortcut action types
24→ */
25→export type ShortcutAction = 'timeline:previous' | 'timeline:next';
26→
27→/**
28→ * Individual keyboard shortcut configuration
29→ */
30→export interface KeyboardShortcut {
31→  action: ShortcutAction;
32→  modifiers: ModifierKey[];
33→  key: ShortcutKey;
34→}
35→
36→/**
37→ * Keyboard event matcher result
38→ */
39→export interface ShortcutMatch {
40→  action: ShortcutAction;
41→  event: KeyboardEvent;
42→}
43→
44→/**
45→ * Complete shortcuts configuration (single set, user-customizable)
46→ */
47→export interface KeyboardShortcutConfig {
48→  previous: KeyboardShortcut;
49→  next: KeyboardShortcut;
50→}
51→
52→/**
53→ * Storage format for shortcuts
54→ */
55→export interface KeyboardShortcutStorage {
56→  shortcuts: KeyboardShortcutConfig;
57→  enabled: boolean;
58→}
