 14→function hashString(input: string): string {
 15→  let h = 2166136261 >>> 0;
 16→  for (let i = 0; i < input.length; i++) {
 17→    h ^= input.charCodeAt(i);
 18→    h = Math.imul(h, 16777619);
 19→  }
 20→  return (h >>> 0).toString(36);
 21→}
