 29→type ExtGlobal = typeof globalThis & {
 30→  chrome?: {
 31→    storage?: {
 32→      sync?: {
 33→        get(k: Record<string, unknown>, cb: (items: Record<string, unknown>) => void): void;
 34→        set?(items: Record<string, unknown>): void;
 35→      };
 36→      onChanged?: {
 37→        addListener(
 38→          cb: (changes: Record<string, { newValue: unknown }>, area: string) => void,
 39→        ): void;
 40→      };
 41→    };
 42→    runtime?: { lastError?: { message: string } };
 43→  };
 44→  browser?: {
