  1→/**
  2→ * KeyboardShortcutService - Manages keyboard shortcuts for timeline navigation
  3→ *
  4→ * Design Patterns:
  5→ * - Singleton: Ensures single instance across application
  6→ * - Strategy: Configurable shortcut matching strategies
  7→ * - Observer: Event-based callback system
  8→ *
  9→ * Features:
 10→ * - Configurable shortcuts with modifier keys
 11→ * - Chrome storage integration for persistence
 12→ * - Type-safe action handling
 13→ * - Collision detection with browser shortcuts
 14→ */
 15→import { StorageKeys } from '@/core/types/common';
 16→import type {
 17→  KeyboardShortcut,
 18→  KeyboardShortcutConfig,
 19→  KeyboardShortcutStorage,
 20→  ModifierKey,
 21→  ShortcutAction,
 22→  ShortcutMatch,
 23→} from '@/core/types/keyboardShortcut';
 24→import { isMac } from '@/core/utils/browser';
 25→
 26→/**
 27→ * Default keyboard shortcuts configuration
 28→ * Using vim-style j/k (convenient, no modifiers needed)
 29→ */
 30→const DEFAULT_SHORTCUTS: KeyboardShortcutConfig = {
 31→  previous: {
 32→    action: 'timeline:previous',
 33→    modifiers: [],
 34→    key: 'k',
 35→  },
 36→  next: {
 37→    action: 'timeline:next',
 38→    modifiers: [],
 39→    key: 'j',
 40→  },
 41→};
 42→
 43→/**
 44→ * Callback type for shortcut actions
 45→ */
 46→export type ShortcutCallback = (action: ShortcutAction, event: KeyboardEvent) => void;
 47→
 48→/**
 49→ * KeyboardShortcutService class
 50→ * Singleton service for managing keyboard shortcuts
 51→ */
 52→export class KeyboardShortcutService {
 53→  private static instance: KeyboardShortcutService | null = null;
 54→
 55→  private config: KeyboardShortcutConfig;
 56→  private enabled: boolean = true;
 57→  private listeners: Set<ShortcutCallback> = new Set();
 58→  private keydownHandler: ((e: KeyboardEvent) => void) | null = null;
 59→  private storageChangeHandler:
 60→    | ((changes: Record<string, chrome.storage.StorageChange>, areaName: string) => void)
 61→    | null = null;
 62→
 63→  private constructor() {
 64→    this.config = DEFAULT_SHORTCUTS;
 65→  }
 66→
 67→  /**
 68→   * Get singleton instance (Factory Pattern)
 69→   */
 70→  static getInstance(): KeyboardShortcutService {
 71→    if (!KeyboardShortcutService.instance) {
 72→      KeyboardShortcutService.instance = new KeyboardShortcutService();
 73→    }
 74→    return KeyboardShortcutService.instance;
 75→  }
 76→
 77→  /**
 78→   * Initialize service: load config and attach listeners
 79→   */
 80→  async init(): Promise<void> {
 81→    await this.loadConfig();
 82→    this.attachKeyboardListener();
 83→    this.attachStorageListener();
 84→  }
 85→
 86→  /**
 87→   * Load configuration from chrome storage
 88→   */
 89→  private async loadConfig(): Promise<void> {
 90→    try {
 91→      if (typeof chrome !== 'undefined' && chrome.storage?.sync) {
 92→        const result = await chrome.storage.sync.get(StorageKeys.TIMELINE_SHORTCUTS);
 93→        const stored = result[StorageKeys.TIMELINE_SHORTCUTS] as
 94→          | KeyboardShortcutStorage
 95→          | undefined;
 96→
 97→        if (stored?.shortcuts) {
 98→          this.config = this.validateConfig(stored.shortcuts)
 99→            ? stored.shortcuts
100→            : DEFAULT_SHORTCUTS;
101→          this.enabled = stored.enabled ?? true;
102→        }
103→      } else {
104→        // Fallback to localStorage
105→        const stored = localStorage.getItem(StorageKeys.TIMELINE_SHORTCUTS);
106→        if (stored) {
107→          const parsed = JSON.parse(stored) as KeyboardShortcutStorage;
108→          this.config = this.validateConfig(parsed.shortcuts)
109→            ? parsed.shortcuts
110→            : DEFAULT_SHORTCUTS;
111→          this.enabled = parsed.enabled ?? true;
112→        }
113→      }
114→    } catch (error) {
115→      console.warn('[KeyboardShortcut] Failed to load config, using defaults:', error);
116→      this.config = DEFAULT_SHORTCUTS;
117→      this.enabled = true;
118→    }
119→  }
120→
121→  /**
122→   * Save configuration to chrome storage
123→   */
124→  async saveConfig(config: KeyboardShortcutConfig, enabled: boolean = this.enabled): Promise<void> {
125→    if (!this.validateConfig(config)) {
126→      throw new Error('Invalid shortcut configuration');
127→    }
128→
129→    this.config = config;
130→    this.enabled = enabled;
131→
132→    const storage: KeyboardShortcutStorage = {
133→      shortcuts: config,
134→      enabled,
135→    };
136→
137→    try {
138→      if (typeof chrome !== 'undefined' && chrome.storage?.sync) {
139→        await chrome.storage.sync.set({ [StorageKeys.TIMELINE_SHORTCUTS]: storage });
140→      } else {
141→        localStorage.setItem(StorageKeys.TIMELINE_SHORTCUTS, JSON.stringify(storage));
142→      }
143→    } catch (error) {
144→      console.error('[KeyboardShortcut] Failed to save config:', error);
145→      throw error;
146→    }
147→  }
148→
149→  /**
150→   * Validate shortcut configuration
151→   */
152→  private validateConfig(config: KeyboardShortcutConfig): boolean {
153→    try {
154→      return !!(
155→        config.previous &&
156→        config.next &&
157→        this.isValidShortcut(config.previous) &&
158→        this.isValidShortcut(config.next)
159→      );
160→    } catch {
161→      return false;
162→    }
163→  }
164→
165→  /**
166→   * Validate individual shortcut
167→   */
168→  private isValidShortcut(shortcut: KeyboardShortcut): boolean {
169→    const validModifiers: ModifierKey[] = ['Alt', 'Ctrl', 'Shift', 'Meta'];
170→
171→    return (
172→      Array.isArray(shortcut.modifiers) &&
173→      shortcut.modifiers.every((m) => validModifiers.includes(m)) &&
174→      typeof shortcut.key === 'string' &&
175→      shortcut.key.length > 0
176→    );
177→  }
178→
179→  /**
180→   * Attach keyboard event listener
181→   */
182→  private attachKeyboardListener(): void {
183→    if (this.keydownHandler) return;
184→
185→    this.keydownHandler = (event: KeyboardEvent) => {
186→      if (!this.enabled) return;
187→
188→      // Ignore shortcuts when user is typing in input fields
189→      if (this.isTypingInInputField(event)) return;
190→
191→      const match = this.matchShortcut(event);
192→      if (match) {
193→        event.preventDefault();
194→        event.stopPropagation();
195→        this.notifyListeners(match.action, event);
196→      }
197→    };
198→
199→    window.addEventListener('keydown', this.keydownHandler, { capture: true });
200→  }
201→
202→  /**
203→   * Check if user is typing in an input field
204→   * Prevents shortcuts from interfering with text input
205→   */
206→  private isTypingInInputField(event: KeyboardEvent): boolean {
207→    const target = event.target as HTMLElement;
208→    if (!target) return false;
209→
210→    const tagName = target.tagName.toLowerCase();
211→    const isEditable = target.isContentEditable;
212→    const isInput = tagName === 'input' || tagName === 'textarea' || tagName === 'select';
213→
214→    return isEditable || isInput;
215→  }
216→
217→  /**
218→   * Attach storage change listener for cross-tab sync
219→   */
220→  private attachStorageListener(): void {
221→    if (typeof chrome !== 'undefined' && chrome.storage?.onChanged) {
222→      this.storageChangeHandler = (changes, areaName) => {
223→        if (areaName !== 'sync') return;
224→        if (changes[StorageKeys.TIMELINE_SHORTCUTS]) {
225→          const newValue = changes[StorageKeys.TIMELINE_SHORTCUTS].newValue as
226→            | KeyboardShortcutStorage
227→            | undefined;
228→          if (newValue?.shortcuts) {
229→            this.config = this.validateConfig(newValue.shortcuts)
230→              ? newValue.shortcuts
231→              : DEFAULT_SHORTCUTS;
232→            this.enabled = newValue.enabled ?? true;
233→          }
234→        }
235→      };
236→
237→      chrome.storage.onChanged.addListener(this.storageChangeHandler);
238→    }
239→  }
240→
241→  /**
242→   * Match keyboard event to shortcut (Strategy Pattern)
243→   */
244→  private matchShortcut(event: KeyboardEvent): ShortcutMatch | null {
245→    const shortcuts = [
246→      { action: 'timeline:previous' as const, config: this.config.previous },
247→      { action: 'timeline:next' as const, config: this.config.next },
248→    ];
249→
250→    // Check if any shortcut matches
251→    for (const { action, config } of shortcuts) {
252→      if (this.isShortcutPressed(event, config)) {
253→        return { action, event };
254→      }
255→    }
256→
257→    return null;
258→  }
259→
260→  /**
261→   * Check if specific shortcut is pressed
262→   */
263→  private isShortcutPressed(event: KeyboardEvent, shortcut: KeyboardShortcut): boolean {
264→    // Check key match
265→    if (event.key !== shortcut.key) return false;
266→
267→    // Check modifier matches
268→    const hasAlt = shortcut.modifiers.includes('Alt');
269→    const hasCtrl = shortcut.modifiers.includes('Ctrl');
270→    const hasShift = shortcut.modifiers.includes('Shift');
271→    const hasMeta = shortcut.modifiers.includes('Meta');
272→
273→    return (
274→      event.altKey === hasAlt &&
275→      event.ctrlKey === hasCtrl &&
276→      event.shiftKey === hasShift &&
277→      event.metaKey === hasMeta
278→    );
279→  }
280→
281→  /**
282→   * Notify all registered listeners (Observer Pattern)
283→   */
284→  private notifyListeners(action: ShortcutAction, event: KeyboardEvent): void {
285→    this.listeners.forEach((callback) => {
286→      try {
287→        callback(action, event);
288→      } catch (error) {
289→        console.error('[KeyboardShortcut] Error in listener callback:', error);
290→      }
291→    });
292→  }
293→
294→  /**
295→   * Register a shortcut callback
296→   */
297→  on(callback: ShortcutCallback): () => void {
298→    this.listeners.add(callback);
299→    // Return unsubscribe function
300→    return () => this.off(callback);
301→  }
302→
