          cb: (changes: Record<string, { newValue: unknown }>, area: string) => void,
        ): void;
      };
    };
    runtime?: { lastError?: { message: string } };
  };
  browser?: {
    storage?: {
      sync?: {
        get(k: Record<string, unknown>): Promise<Record<string, unknown>>;
        set?(items: Record<string, unknown>): void;
      };
      onChanged?: {
